#include <iostream>

using namespace std;

int main()
{
    int i = 1;

    while (i <= 5)
    {
        cout << i << endl;
        i++;
    }

    return 0;
}

int num;
cin >> num;

while (num != 0)
{
    cout << "You entered: " << num << endl;
    cin >> num;
}
cout << "Done.";

int i = 1;

while (i <= 5)
{
    cout << i << endl; // i is never changed here!
}

int i = 10;

while (i <= 5) // false from the very start
{
    cout << i << endl;
}
cout << "Loop skipped entirely.";

